int remove_key(const char *key) {
    node_t *cur = g_head, *prev = NULL;
    while (cur != NULL) {
        if (strcmp(cur->key, key) == 0) {
            if (prev == NULL) g_head = cur->next; else prev->next = cur->next;
            free(cur);
            audit_removal(key);
            return RC_OK;
        }
        prev = cur; cur = cur->next;
    }
    return RC_NOTFOUND;
}

int count_keys(void) {
    int n = 0;
    for (node_t *c = g_head; c; c = c->next) n++;
    return n;
}
